INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_diff_201','モバイルインターネット採用の実証研究（アジア新興国）','Mobile Internet Adoption in Asian Emerging Markets','インド・中国・インドネシアなどのアジア新興国におけるモバイルインターネット採用の規定因を検討した実証研究群。インフラ整備、価格感度、識字率、信頼といった地域固有の障壁が採用プロセスに大きく影響することを明らかにした。TAMとUTAUTをローカライズした拡張モデルが用いられることが多い。','新興国市場でのデジタル技術普及に関する政策立案と企業戦略に直結した実証知見を提供した。','diffusion_adoption_user','C_processes','普及理論・新興国適用','2005','meso','diffusion','pragmatic_adoption','["Venkatesh, V.", "Donner, J.", "Qiang, C.Z."]','["Donner (2008) The Rules of Beeping", "Qiang et al. (2011) Mobile Applications for Agriculture"]','モバイル採用,新興国,デジタルデバイド,TAM拡張','mobile adoption,emerging markets,digital divide,TAM extension'),
('inno_diff_202','ソーシャルメディア採用行動のメタ分析','Meta-Analysis of Social Media Adoption Behavior','TAM・UTAUT・イノベーション普及理論を用いたソーシャルメディア採用研究のメタ分析。知覚有用性・知覚易用性・社会的影響・ヘドニック動機の効果量を統合し、先行研究の不整合を整理した。サンプル特性（年齢・文化圏・SNSプラットフォーム種別）によって効果量が有意に異なることが示された。','採用研究における変数間関係の強さを定量化し、将来研究の設計と政策立案に科学的根拠を提供した。','diffusion_adoption_user','C_processes','メタ分析・採用研究','2015','micro','adoption','evidence_synthesis','["Cao, X.", "Huang, C.", "Dwivedi, Y.K."]','["Dwivedi et al. (2017) Meta-analysis of TAM", "Huang (2022) SNS meta-analysis"]','メタ分析,ソーシャルメディア,採用行動,効果量','meta-analysis,social media,adoption behavior,effect size'),
('inno_diff_203','電子政府サービス採用モデル（UTAUT2拡張）','E-Government Service Adoption Model (UTAUT2 Extension)','UTAUT2をベースに信頼・プライバシー懸念・制度的圧力を追加した電子政府採用モデル。市民の行政デジタルサービス利用意図を規定する要因を複数国で比較検討した。高齢者・低教育層など社会的弱者の利用障壁を特定することが主要な政策インプリケーションとなっている。','デジタル行政の包摂性向上に向けた政策設計と官民協働モデルの構築に貢献した。','diffusion_adoption_user','C_processes','電子政府採用研究','2012','meso','adoption','trust_based_adoption','["Carter, L.", "Weerakkody, V.", "Al-Hujran, O."]','["Carter & Belanger (2005) E-gov adoption", "Weerakkody et al. (2013) E-gov UTAUT"]','電子政府,UTAUT2,信頼,市民採用','e-government,UTAUT2,trust,citizen adoption'),
('inno_diff_204','クロスナショナル普及比較研究（ホフステード文化次元との統合）','Cross-National Diffusion Comparison with Hofstede Cultural Dimensions','ホフステードの文化次元（個人主義・権力格差・不確実性回避・長期志向）とイノベーション普及速度の関係を複数国データで検証した研究系譜。文化的コンテキストが採用カーブの形状・傾きに与える影響を定量化し、文化論的普及理論の基盤を形成した。','グローバル展開における市場適応戦略の理論的根拠を提供し、文化敏感型普及モデルの構築を促した。','diffusion_adoption_user','C_processes','文化的普及研究','1991','meso','diffusion','cultural_framing','["Hofstede, G.", "Straub, D.", "Erumban, A.A."]','["Straub et al. (1997) Cross-cultural IT adoption", "Erumban & de Jong (2006) ICT adoption Hofstede"]','文化次元,クロスナショナル,普及速度,個人主義','cultural dimensions,cross-national,diffusion speed,individualism'),
('inno_diff_205','プラットフォームエコシステムにおける採用カスケード','Adoption Cascades in Platform Ecosystems','多面市場・プラットフォームビジネスにおける採用の連鎖的拡散メカニズムを分析したモデル。一方の市場（例：開発者）での採用増加が他方（利用者）の採用を誘発するクロスサイドネットワーク効果を採用普及理論と統合した。鶏卵問題の解消戦略としてのシードユーザー確保の重要性も論じられる。','プラットフォームビジネスの普及戦略と規制政策（独禁法等）に影響を与えた理論的枠組みを提供した。','diffusion_adoption_user','C_processes','プラットフォーム理論','2003','macro','diffusion','network_effect_adoption','["Rochet, J.C.", "Tirole, J.", "Parker, G.G."]','["Rochet & Tirole (2003) Platform Competition", "Parker & Van Alstyne (2016) Platform Revolution"]','プラットフォーム,クロスサイドネットワーク,採用カスケード,多面市場','platform,cross-side network,adoption cascade,multi-sided market'),
('inno_diff_206','農業技術採用と農家の意思決定（途上国実証）','Agricultural Technology Adoption and Farmer Decision-Making in Developing Countries','アフリカ・南アジアを中心とした農家による改良種子・肥料・灌漑技術の採用行動を分析した実証研究群。情報の非対称性・リスク回避・流動性制約・社会的学習が採用に与える影響を解明した。ランダム化比較試験（RCT）が多用され、行動経済学的視点を取り入れた研究が増加している。','農業普及政策と開発援助プログラム設計の科学的基盤として世界銀行・FAOの政策に影響を与えた。','diffusion_adoption_user','C_processes','農業普及・開発経済学','1985','micro','adoption','risk_aversion_adoption','["Foster, A.D.", "Rosenzweig, M.R.", "Suri, T."]','["Foster & Rosenzweig (1995) Learning by Doing", "Suri (2011) Complementarities in Adoption"]','農業技術採用,途上国,社会的学習,リスク回避','agricultural technology adoption,developing countries,social learning,risk aversion'),
('inno_diff_207','電気自動車採用の消費者行動研究','Consumer Behavior Research on Electric Vehicle Adoption','電気自動車（EV）採用を規定する態度・規範・知覚障壁・補助政策の効果を検証した研究系譜。TPB（計画行動理論）・NAM（規範活性化モデル）・TAMの統合モデルが広く用いられ、航続距離不安・充電インフラ・価格感度が主要障壁として繰り返し確認されている。','EV普及政策（補助金・インフラ整備）と自動車産業の市場戦略策定に直結した実証知見を提供した。','diffusion_adoption_user','C_processes','グリーン技術採用研究','2010','micro','adoption','environmental_norm_adoption','["Egbue, O.", "Schuitema, G.", "Helveston, J.P."]','["Egbue & Long (2012) EV Adoption Barriers", "Helveston et al. (2015) China EV adoption"]','電気自動車,採用障壁,航続距離不安,TPB','electric vehicle,adoption barriers,range anxiety,TPB'),
('inno_diff_208','ウェアラブルデバイス採用とヘルスデータ共有行動','Wearable Device Adoption and Health Data Sharing Behavior','スマートウォッチ・フィットネストラッカーなどウェアラブルの採用とその後の継続使用・ヘルスデータ共有行動を分析した研究。UTAUT2・プライバシー計算モデル・習慣形成理論が統合的に用いられる。ヘルスリテラシーとデータ自律性認識が採用後の行動を強く規定することが明らかにされた。','ヘルステックのプロダクト設計とデータ利活用ポリシーに対して実証的根拠を提供した。','diffusion_adoption_user','C_processes','ヘルステック採用研究','2015','micro','adoption','habit_formation_adoption','["Gao, Y.", "Li, H.", "Shim, J.P."]','["Gao & Bai (2014) Wearable adoption", "Shim et al. (2015) Health wearable UTAUT2"]','ウェアラブル,ヘルスデータ,継続使用,プライバシー','wearable,health data,continued use,privacy'),
('inno_diff_209','クラウドコンピューティング採用における組織的決定要因','Organizational Determinants of Cloud Computing Adoption','TOE（技術・組織・環境）フレームワークと制度理論を統合したクラウド採用研究。技術準備度・トップマネジメント支持・競合圧力・規制環境が組織のクラウド移行を規定する構造を解明した。SME（中小企業）と大企業で採用規定因の重みが異なることも示された。','クラウドサービスプロバイダーの市場戦略とCIO/CTOの意思決定支援に活用される知見を提供した。','diffusion_adoption_user','C_processes','組織採用研究・TOEフレームワーク','2010','meso','adoption','organizational_adoption','["Low, C.", "Oliveira, T.", "Martins, M.F."]','["Low et al. (2011) Cloud TOE model", "Oliveira et al. (2014) Cloud adoption multi-country"]','クラウドコンピューティング,TOEフレームワーク,組織採用,SME','cloud computing,TOE framework,organizational adoption,SME'),
('inno_diff_210','テレメディシン採用の医療従事者研究','Healthcare Provider Adoption of Telemedicine','医師・看護師・薬剤師によるテレメディシン（遠隔医療）採用の規定因を検討した研究群。TAM・UTAUT・専門職アイデンティティ理論が統合される。COVID-19パンデミックを契機とした急速普及期の研究が蓄積し、制度的強制・利便性・患者アウトカムへの懸念が複雑に絡み合う採用構造が解明された。','遠隔医療政策・診療報酬制度設計・医療機関のデジタル変革戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','医療技術採用研究','2000','micro','adoption','professional_identity_adoption','["Gagnon, M.P.", "Scott, R.E.", "Greenhalgh, T."]','["Gagnon et al. (2012) Telemedicine adoption", "Greenhalgh et al. (2017) NASSS framework"]','テレメディシン,医療従事者採用,遠隔医療,TAM','telemedicine,healthcare provider adoption,remote care,TAM'),
('inno_diff_211','ビッグデータ分析採用の組織能力論的視点','Organizational Capability Perspective on Big Data Analytics Adoption','ダイナミック・ケイパビリティ論とリソースベース理論を基盤に、組織のビッグデータ分析採用を規定するデータインフラ・分析人材・データ文化の三要素を分析した研究。IT採用の組織学習論的側面を強調し、採用後の能力蓄積プロセスを追跡したロンジチュード研究も含まれる。','企業のデジタル変革戦略・CDO（最高データ責任者）設置の意思決定に影響を与えた理論枠組みを提供した。','diffusion_adoption_user','C_processes','組織採用研究・能力論','2013','meso','adoption','capability_building_adoption','["Wamba, S.F.", "Gunasekaran, A.", "Akter, S."]','["Wamba et al. (2017) Big data analytics capabilities", "Akter et al. (2016) BDA and firm performance"]','ビッグデータ分析,組織能力,ダイナミックケイパビリティ,データ文化','big data analytics,organizational capability,dynamic capabilities,data culture'),
('inno_diff_212','フィンテック採用の消費者行動研究（UTAUT2適用）','Consumer Behavior in Fintech Adoption (UTAUT2 Application)','モバイル決済・クラウドファンディング・ロボアドバイザーなどフィンテックサービスへの消費者採用をUTAUT2で分析した研究群。快楽的動機・習慣・金融リテラシー・セキュリティ懸念が特に重要な規定因として確認されている。新興国での急速普及を説明するための文化的修正モデルも提案されている。','フィンテック企業のUXデザイン・マーケティング戦略と金融規制当局の政策立案に影響を与えた。','diffusion_adoption_user','C_processes','フィンテック採用研究','2016','micro','adoption','hedonic_motivation_adoption','["Baptista, G.", "Oliveira, T.", "Shaw, N."]','["Baptista & Oliveira (2016) Mobile payment UTAUT2", "Shaw & Kesharwani (2019) Fintech adoption"]','フィンテック,モバイル決済,UTAUT2,金融リテラシー','fintech,mobile payment,UTAUT2,financial literacy'),
('inno_diff_213','人工知能ツール採用の組織変革研究','Organizational Change Research on AI Tool Adoption','業務用AIツール（チャットボット・予測分析・自動意思決定）の組織採用プロセスを変革管理論と結びつけた研究。Kotter 8段階モデル・Lewinの変化モデルとITアライメント理論を統合し、AI採用における抵抗管理・チェンジチャンピオン・継続教育の重要性を解明した。','企業のAI導入プロジェクト管理とCHRO（最高人事責任者）の育成戦略に実践的知見を提供した。','diffusion_adoption_user','C_processes','AI採用・変革管理研究','2018','meso','adoption','change_management_adoption','["Davenport, T.H.", "Brynjolfsson, E.", "Kolbjornsrud, V."]','["Davenport & Ronanki (2018) AI in the Enterprise", "Brynjolfsson & McAfee (2014) Second Machine Age"]','AI採用,組織変革,変革管理,チェンジマネジメント','AI adoption,organizational change,change management,digital transformation'),
('inno_diff_214','ブロックチェーン技術採用の産業別分析','Industry-Specific Analysis of Blockchain Technology Adoption','金融・サプライチェーン・ヘルスケア・不動産などセクター別のブロックチェーン採用規定因を分析した研究群。TOEフレームワーク・イノベーション特性理論・制度理論が主に用いられる。スケーラビリティ・相互運用性・規制不確実性が汎用的な採用障壁として繰り返し確認されている。','ブロックチェーンのユースケース選定と規制サンドボックス政策設計に影響を与えた実証知見を提供した。','diffusion_adoption_user','C_processes','ブロックチェーン採用研究','2017','meso','adoption','institutional_trust_adoption','["Kshetri, N.", "Janssen, M.", "Zavolokina, L."]','["Kshetri (2018) Blockchain roles in meeting key supply chain management objectives", "Janssen et al. (2020) Blockchain for government"]','ブロックチェーン,産業別採用,TOE,相互運用性','blockchain,industry-specific adoption,TOE,interoperability'),
('inno_diff_215','教育テクノロジー採用の教師研究（TPACK統合）','Teacher Adoption of Educational Technology (TPACK Integration)','TPACK（技術的教科教育学的知識）フレームワークとUTAUT・TAMを統合した教師によるEdTech採用研究。教科内容知識・教育学的知識・技術知識の三要素の統合度合いが採用継続に直接影響することを示した。COVID-19による遠隔教育移行期の研究が急増した。','教員研修プログラム設計とEdTechプラットフォームのUX改善に理論的根拠を提供した。','diffusion_adoption_user','C_processes','EdTech採用・教師研究','2006','micro','adoption','competence_based_adoption','["Mishra, P.", "Koehler, M.J.", "Ertmer, P.A."]','["Mishra & Koehler (2006) TPACK", "Ertmer et al. (2012) Teacher beliefs and technology integration"]','TPACK,EdTech,教師採用,遠隔教育','TPACK,EdTech,teacher adoption,distance education'),
('inno_diff_216','スマートシティ技術の市民採用研究','Citizen Adoption of Smart City Technologies','スマートメーター・デジタル市民サービス・都市センサーネットワークなどスマートシティ技術への市民採用を分析した研究。プライバシー懸念・公共価値・デジタルリテラシーが主要規定因として特定されている。参加型ガバナンスと採用促進の関係も論じられる。','スマートシティ計画の住民エンゲージメント戦略と公共サービスデジタル化政策に貢献した。','diffusion_adoption_user','C_processes','スマートシティ採用研究','2014','meso','adoption','public_value_adoption','["Bélissent, J.", "Neirotti, P.", "Vanolo, A."]','["Neirotti et al. (2014) Smart cities overview", "Vanolo (2014) Smartmentality"]','スマートシティ,市民採用,プライバシー,デジタルリテラシー','smart city,citizen adoption,privacy,digital literacy'),
('inno_diff_217','継続使用意図理論（ECT: 期待確認モデル）','Expectation Confirmation Theory of Continued IS Use','Oliver の消費者満足理論を情報システムの継続使用に適用したBhattacherjee（2001）のモデル。採用後の期待確認度・知覚有用性・満足度が継続使用意図に影響する構造を示した。採用「前」だけでなく「後」の行動を説明する理論として広く参照される。','ITシステムの継続率・解約率を予測するモデルとして産業界でも活用され、CXM（顧客体験管理）の理論的基盤の一つとなった。','diffusion_adoption_user','C_processes','継続使用・満足研究','2001','micro','adoption','expectation_confirmation','["Bhattacherjee, A.", "Oliver, R.L."]','["Bhattacherjee (2001) ECT of continued IS use", "Oliver (1980) Cognitive model of satisfaction"]','継続使用,期待確認,満足度,ECT','continued use,expectation confirmation,satisfaction,ECT'),
('inno_diff_218','D&M情報システム成功モデル','DeLone and McLean Information Systems Success Model','DeLone & McLean（1992, 2003）による情報システム成功の多次元モデル。システム品質・情報品質・サービス品質・使用・ユーザー満足・ネット便益の六要素が相互影響する構造を示す。採用後の成功評価フレームとして電子商取引・電子政府・ヘルスITなど多分野で広く応用されている。','情報システム評価・投資対効果測定の標準フレームとして学術・実務の双方で広く参照される基盤理論を提供した。','diffusion_adoption_user','C_processes','IS評価・成功研究','1992','meso','adoption','multi_dimensional_success','["DeLone, W.H.", "McLean, E.R."]','["DeLone & McLean (1992) IS success model", "DeLone & McLean (2003) Updated IS success model"]','ISシステム成功,品質,ユーザー満足,ネット便益','IS success,quality,user satisfaction,net benefits'),
('inno_diff_219','拡張UTAUT（UTAUT3）の提案と検証','Extended UTAUT (UTAUT3) Proposal and Validation','Venkatesh et al. のUTAUTをさらに拡張し、エモーショナルデザイン・AIインタラクション・データ倫理懸念を組み込んだUTAUT3の提案研究。AI採用・XR（拡張現実）採用などの新技術文脈で適用されている。UTAUT2からUTAUT3への理論的発展とその限界が議論されている。','新興技術採用研究の方法論的基盤をアップデートし、今後の採用研究の標準モデル候補として議論されている。','diffusion_adoption_user','C_processes','UTAUT発展研究','2021','micro','adoption','extended_adoption_model','["Venkatesh, V.", "Morris, M.G.", "Dwivedi, Y.K."]','["Dwivedi et al. (2019) UTAUT2 critique", "Venkatesh et al. (2016) UTAUT review"]','UTAUT3,拡張採用モデル,AIインタラクション,データ倫理','UTAUT3,extended adoption model,AI interaction,data ethics'),
('inno_diff_220','ソーシャルコマース採用の実証研究','Empirical Research on Social Commerce Adoption','SNSを活用した購買活動（ソーシャルコマース）への参加・採用を分析した研究。社会的支援・共有・共同購買という三つのソーシャル要素が採用意図に影響する構造を解明した。WeChat・Instagram・TikTokなどプラットフォーム別の比較研究も蓄積されている。','Eコマース企業のSNS戦略と消費者エンゲージメント設計に理論的根拠を提供した。','diffusion_adoption_user','C_processes','ソーシャルコマース採用研究','2011','micro','adoption','social_influence_adoption','["Huang, Z.", "Benyoucef, M.", "Zhang, H."]','["Huang & Benyoucef (2013) S-commerce model", "Zhang et al. (2014) Social commerce adoption"]','ソーシャルコマース,SNS購買,社会的影響,採用意図','social commerce,SNS shopping,social influence,adoption intention'),
('inno_diff_221','オープンソースソフトウェア採用の組織的決定要因','Organizational Determinants of Open Source Software Adoption','企業・政府機関によるOSS採用を規定するコスト便益分析・ベンダーロックイン回避・コミュニティサポート・ライセンスリスクの諸要因を分析した研究群。TOEフレームワークとオープンイノベーション理論を統合した枠組みが提案されている。','公共機関のOSS調達政策と民間企業のITアーキテクチャ戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','OSSエコシステム採用研究','2005','meso','adoption','cost_benefit_adoption','["Dedrick, J.", "West, J.", "Lerner, J."]','["Dedrick & West (2003) Why firms adopt OSS", "Lerner & Tirole (2002) Economics of OSS"]','オープンソース,OSS採用,ベンダーロックイン,TOE','open source,OSS adoption,vendor lock-in,TOE'),
('inno_diff_222','クラウドソーシングプラットフォーム参加者採用研究','Participant Adoption Research on Crowdsourcing Platforms','Amazon Mechanical Turk・Topcoder・Kaggleなどクラウドソーシングプラットフォームへの参加者採用と継続参加行動を分析した研究。内発的動機・経済的インセンティブ・ゲーミフィケーション・コミュニティ帰属感が採用と定着に影響することが示された。','プラットフォームの参加者獲得戦略とクラウドワーク政策の科学的根拠を提供した。','diffusion_adoption_user','C_processes','クラウドソーシング参加研究','2012','micro','adoption','intrinsic_motivation_adoption','["Zhao, Y.", "Zhu, Q.", "Brabham, D.C."]','["Brabham (2013) Crowdsourcing", "Zhao & Zhu (2014) Effects of extrinsic motivation on crowdsourcing"]','クラウドソーシング,参加動機,ゲーミフィケーション,内発的動機','crowdsourcing,participation motivation,gamification,intrinsic motivation'),
('inno_diff_223','インターネットオブシングス（IoT）採用の消費者研究','Consumer Research on Internet of Things Adoption','スマートホームデバイス・コネクテッドカー・産業IoTへの採用を消費者・企業の双方から分析した研究群。セキュリティ・プライバシー・相互運用性・習慣破壊性が主要障壁として繰り返し確認されている。採用後の生活パターン変容を追跡したエスノグラフィック研究も含まれる。','IoT製品設計・セキュリティ標準策定・スマートホーム市場戦略に貢献する実証知見を提供した。','diffusion_adoption_user','C_processes','IoT採用研究','2015','micro','adoption','security_concern_adoption','["Blythe, J.M.", "Coventry, L.", "Sicari, S."]','["Blythe & Johnson (2019) Smart home IoT", "Sicari et al. (2015) IoT security survey"]','IoT,スマートホーム,セキュリティ,プライバシー','IoT,smart home,security,privacy'),
('inno_diff_224','デジタルヘルスアプリ採用とエンゲージメント研究','Digital Health App Adoption and Engagement Research','健康管理・慢性疾患管理・メンタルヘルス支援アプリへの採用と継続的エンゲージメントを分析した研究。採用意図と実際の長期使用（エンゲージメント）の乖離が重要な課題として取り上げられ、行動変容理論との統合が試みられている。','患者エンゲージメント向上を目指すヘルスアプリ開発者と医療機関のデジタルヘルス戦略に貢献した。','diffusion_adoption_user','C_processes','デジタルヘルス採用研究','2016','micro','adoption','behavior_change_adoption','["Pew Research", "Schroeder, J.", "Baumel, A."]','["Baumel et al. (2019) Health app engagement", "Schroeder et al. (2018) Engagement with digital health"]','デジタルヘルス,健康アプリ,エンゲージメント,行動変容','digital health,health app,engagement,behavior change'),
('inno_diff_225','VR/AR技術採用の消費者行動研究','Consumer Behavior Research on VR/AR Technology Adoption','バーチャルリアリティ・拡張現実技術への消費者採用をTAM・フロー理論・臨場感モデルと統合して分析した研究群。没入感・インタラクティビティ・身体化認知が採用態度に独自の影響を与えることを示した。エンターテインメント・教育・小売などセクター別の比較研究も蓄積されている。','VRコンテンツ開発者・XRハードウェアメーカーのユーザー体験設計と市場投入戦略に貢献した。','diffusion_adoption_user','C_processes','XR技術採用研究','2017','micro','adoption','immersion_based_adoption','["Huang, T.L.", "Liao, S.", "Hammouri, Q."]','["Huang & Liao (2017) VR tourism", "Hammouri (2018) AR adoption TAM"]','VR,AR,拡張現実,没入感,採用','VR,AR,augmented reality,immersion,adoption'),
('inno_diff_226','オンライン学習プラットフォーム採用のメタ分析','Meta-Analysis of Online Learning Platform Adoption','MOOCs・LMS・同期型オンライン授業への学習者採用を分析した研究のメタ分析。知覚有用性・自己効力感・インタラクティビティ・コース設計品質の効果量を統合した。修了率の低さ（ドロップアウト問題）と採用後の離脱行動も主要テーマとなっている。','オンライン教育プラットフォーム設計と教育政策立案に科学的根拠を提供した。','diffusion_adoption_user','C_processes','EdTech・eラーニング採用研究','2014','micro','adoption','self_efficacy_adoption','["Liaw, S.S.", "Huang, H.M.", "Gamage, D."]','["Liaw (2008) e-learning TAM", "Gamage et al. (2020) MOOCs adoption meta-analysis"]','オンライン学習,MOOC,修了率,自己効力感','online learning,MOOC,completion rate,self-efficacy'),
('inno_diff_227','行動経済学的採用障壁研究（現状維持バイアスの役割）','Behavioral Economics of Adoption Barriers: The Role of Status Quo Bias','現状維持バイアス・損失回避・サンクコスト効果など行動経済学的メカニズムがイノベーション採用を妨げる構造を分析した研究群。Samuelson & Zeckhauser の現状維持バイアス論を採用文脈に適用し、ナッジ設計による採用促進の可能性を検討した。','政策立案者のナッジ設計と企業のオンボーディング戦略に行動経済学的根拠を提供した。','diffusion_adoption_user','C_processes','行動経済学的採用研究','2003','micro','adoption','status_quo_bias','["Samuelson, W.", "Zeckhauser, R.", "Thaler, R.H."]','["Samuelson & Zeckhauser (1988) Status quo bias", "Thaler & Sunstein (2008) Nudge"]','現状維持バイアス,損失回避,ナッジ,採用障壁','status quo bias,loss aversion,nudge,adoption barriers'),
('inno_diff_228','ロボット採用と人間-ロボット協働研究','Robot Adoption and Human-Robot Collaboration Research','製造業・医療・サービス業での産業用ロボット・協働ロボット（コボット）採用を分析した研究。技術受容だけでなく、感情的受容・安全知覚・雇用不安・技能再訓練の意欲が採用態度に影響することを示した。人間-ロボット協働（HRC）の行動インタフェース設計研究との統合も進んでいる。','製造業のオートメーション戦略・労働政策・ロボティクス製品設計に対して実証的根拠を提供した。','diffusion_adoption_user','C_processes','ロボティクス採用研究','2012','meso','adoption','anthropomorphic_adoption','["Heerink, M.", "Dautenhahn, K.", "Bröhl, C."]','["Heerink et al. (2010) UTAUT robotics", "Dautenhahn (2007) Socially intelligent robots"]','ロボット採用,人間-ロボット協働,コボット,感情的受容','robot adoption,human-robot collaboration,cobot,emotional acceptance'),
('inno_diff_229','サブスクリプションモデル採用の消費者研究','Consumer Research on Subscription Model Adoption','SaaS・ストリーミングサービス・D2Cサブスクリプションへの採用と解約（チャーン）行動を分析した研究群。知覚価値・柔軟性・切替コスト・慣性が採用と継続に影響することが示された。フリーミアムからの転換率分析も含まれる。','サブスクリプションビジネスの価格設計・顧客維持戦略・チャーン予測モデル開発に貢献した。','diffusion_adoption_user','C_processes','サブスクリプション採用研究','2014','micro','adoption','perceived_value_adoption','["Tzuo, T.", "Weisert, G.", "Gupta, S."]','["Tzuo & Weisert (2018) Subscribed", "Gupta & Mela (2008) What is a free customer worth"]','サブスクリプション,チャーン,フリーミアム,知覚価値','subscription,churn,freemium,perceived value'),
('inno_diff_230','再生可能エネルギー技術採用の家庭研究','Household Adoption of Renewable Energy Technologies','太陽光発電・家庭用蓄電池・ヒートポンプなど再生可能エネルギー技術の家庭採用を分析した研究群。TAM・TPB・規範活性化モデルに加え、エネルギー貧困・住宅所有形態・近隣効果が採用規定因として確認されている。ソーシャルラーニングによる普及促進メカニズムも解明された。','再エネ補助金政策・ネットメータリング制度設計・グリーン金融商品開発に実証的根拠を提供した。','diffusion_adoption_user','C_processes','再生可能エネルギー採用研究','2008','micro','adoption','norm_activation_adoption','["Faiers, A.", "Neame, C.", "Claudy, M.C."]','["Faiers & Neame (2006) Solar PV adoption", "Claudy et al. (2011) Renewable energy adoption barriers"]','再生可能エネルギー,家庭採用,ソーラー,規範活性化モデル','renewable energy,household adoption,solar PV,norm activation model'),
('inno_diff_231','デジタル通貨・暗号資産採用研究','Digital Currency and Cryptocurrency Adoption Research','ビットコイン・イーサリアム・CBDC（中央銀行デジタル通貨）への採用を分析した研究群。革新性・匿名性・投機的動機・規制リスクが採用態度に影響することが示された。エルサルバドルのビットコイン法定通貨化など政策実験の分析も蓄積されている。','暗号資産規制政策・CBDC設計・金融包摂戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','暗号資産採用研究','2017','micro','adoption','speculative_adoption','["Folkinshteyn, D.", "Lennon, M.", "Hyun, S."]','["Folkinshteyn & Lennon (2016) Braving Bitcoin", "Hyun et al. (2021) Crypto adoption"]','暗号資産,ビットコイン,CBDC,金融包摂','cryptocurrency,Bitcoin,CBDC,financial inclusion'),
('inno_diff_232','シェアリングエコノミーサービス採用研究','Sharing Economy Service Adoption Research','Uber・Airbnb・TaskRabbitなどシェアリングエコノミーへの採用と信頼形成を分析した研究群。評判システム・デジタル信頼・サービス品質・規制不確実性が採用態度に影響することが示された。供給側（プロバイダー）の採用と需要側（消費者）の採用を区別した比較研究も蓄積されている。','プラットフォームのレーティング設計と都市交通・宿泊規制政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','シェアリングエコノミー採用研究','2015','meso','adoption','platform_trust_adoption','["Hamari, J.", "Sjöklint, M.", "Ukkonen, A."]','["Hamari et al. (2016) Sharing economy adoption", "Tussyadiah (2016) Airbnb adoption"]','シェアリングエコノミー,Uber,Airbnb,デジタル信頼','sharing economy,Uber,Airbnb,digital trust'),
('inno_diff_233','3Dプリンティング技術採用の産業研究','Industry Adoption Research on 3D Printing Technology','製造業・医療・建設・ファッションにおける3Dプリンティング（AM：付加製造）採用の規定因を分析した研究群。プロトタイピングからエンドユース製品製造への移行障壁・材料コスト・精度要件・IP課題が主要テーマとなっている。','製造業の設備投資意思決定と産業政策（国家AM戦略）の科学的根拠を提供した。','diffusion_adoption_user','C_processes','先端製造技術採用研究','2013','meso','adoption','complexity_adoption','["Berman, B.", "Huang, S.H.", "Liu, P."]','["Berman (2012) 3D printing overview", "Huang et al. (2013) AM barriers"]','3Dプリンティング,付加製造,製造業採用,プロトタイピング','3D printing,additive manufacturing,industry adoption,prototyping'),
('inno_diff_234','デジタル農業技術採用と農家情報行動','Digital Agricultural Technology Adoption and Farmer Information Behavior','精密農業・ドローン農薬散布・農業IoTなどデジタル農業技術の採用において、農家の情報探索行動・情報源信頼・普及員との関係が採用を規定する構造を分析した研究。農家の技術自己効力感とデジタルリテラシーが特に重要な規定因として確認されている。','農業DX政策と農業普及サービスのデジタル改革に向けた実証的根拠を提供した。','diffusion_adoption_user','C_processes','農業普及・デジタル農業研究','2018','micro','adoption','information_behavior_adoption','["Pierpaoli, E.", "Carli, G.", "Pignone, E."]','["Pierpaoli et al. (2013) Smart farming drivers", "Carolan (2020) Precision agriculture adoption"]','デジタル農業,精密農業,農家採用,農業IoT','digital agriculture,precision farming,farmer adoption,agricultural IoT'),
('inno_diff_235','ヘルスIT採用の患者研究（PHR・患者ポータル）','Patient Adoption of Health IT: Personal Health Records and Patient Portals','電子健康記録（PHR）・患者ポータル・医療SNSへの患者採用を分析した研究群。ヘルスリテラシー・情報信頼・医療機関との関係性・プライバシー懸念が採用規定因として確認されている。低所得層・高齢者・慢性疾患患者の採用格差も重要テーマとなっている。','患者エンパワーメント政策とヘルスIT設計の包摂性向上に実証的根拠を提供した。','diffusion_adoption_user','C_processes','患者採用・ヘルスIT研究','2010','micro','adoption','health_literacy_adoption','["Yamin, C.K.", "Emani, S.", "Sittig, D.F."]','["Yamin et al. (2011) PHR adoption barriers", "Sittig & Singh (2012) EHR benefits"]','患者採用,PHR,患者ポータル,ヘルスリテラシー','patient adoption,PHR,patient portal,health literacy'),
('inno_diff_236','スマートグリッド採用の家庭・産業研究','Household and Industrial Smart Grid Adoption Research','スマートメーター・需要応答システム・スマートグリッドへの家庭・企業採用を分析した研究群。エネルギー節約動機・時間帯別料金理解・プライバシー懸念・技術信頼が採用規定因として確認されている。電力会社と消費者のインタラクション設計も重要テーマとなっている。','エネルギー規制政策・電力会社のデジタル変革戦略・スマートメーター展開計画に貢献した。','diffusion_adoption_user','C_processes','スマートエネルギー採用研究','2011','meso','adoption','energy_behavior_adoption','["Krishnamurti, T.", "Chen, C.F.", "Darby, S."]','["Krishnamurti et al. (2012) Smart meter attitudes", "Darby (2010) Smart technology in home"]','スマートグリッド,スマートメーター,需要応答,エネルギー行動','smart grid,smart meter,demand response,energy behavior'),
('inno_diff_237','音声インタフェース・会話AIの採用研究','Adoption Research on Voice Interfaces and Conversational AI','Amazon Alexa・Google Assistant・企業チャットボットなど音声UI・会話AIへの採用をUTAUT・プライバシー計算・感情的信頼モデルで分析した研究群。会話の自然性・誤認識への不満・プライバシー懸念（常時聴取不安）が主要障壁として確認されている。','スマートスピーカー製品設計・会話AI UX改善・プライバシー政策立案に貢献する実証知見を提供した。','diffusion_adoption_user','C_processes','会話AI採用研究','2018','micro','adoption','conversational_trust_adoption','["Ammari, T.", "Park, J.", "McLean, G."]','["Ammari et al. (2019) Alexa adoption", "McLean & Osei-Frimpong (2019) Voice assistants"]','音声インタフェース,会話AI,スマートスピーカー,プライバシー','voice interface,conversational AI,smart speaker,privacy'),
('inno_diff_238','自律走行車採用の公衆受容研究','Public Acceptance Research on Autonomous Vehicle Adoption','レベル3〜5の自律走行車への消費者・社会的受容を分析した研究群。信頼・安全知覚・制御喪失不安・倫理的懸念（トロッコ問題型）・規制整備状況が採用態度に影響することが示された。文化間比較研究も増加している。','自動運転規制政策・自動車メーカーの市場投入戦略・交通インフラ計画に科学的根拠を提供した。','diffusion_adoption_user','C_processes','自動運転採用研究','2017','meso','adoption','trust_in_automation','["Bansal, P.", "Kockelman, K.M.", "Kyriakidis, M."]','["Bansal et al. (2016) Autonomous vehicles acceptance", "Kyriakidis et al. (2015) AV survey"]','自律走行車,公衆受容,信頼,安全知覚','autonomous vehicle,public acceptance,trust,safety perception'),
('inno_diff_239','モバイルヘルス（mHealth）採用の途上国研究','Mobile Health Adoption Research in Developing Countries','アフリカ・南アジアのmHealthアプリ・SMS健康サービスへの採用を分析した研究群。電話普及率・ネットワーク信頼性・ヘルスワーカー役割・コスト感度が採用規定因として確認されている。WHOのmHealth政策との整合性も議論されている。','途上国の医療アクセス格差是正政策と国際保健NGOのデジタルヘルス戦略に貢献した。','diffusion_adoption_user','C_processes','mHealth採用・国際保健研究','2012','micro','adoption','access_based_adoption','["Lester, R.T.", "Aranda-Jan, C.B.", "Patel, S."]','["Lester et al. (2010) mHealth HIV", "Aranda-Jan et al. (2014) mHealth Africa review"]','mHealth,途上国,モバイル医療,SMS健康','mHealth,developing countries,mobile health,SMS health'),
('inno_diff_240','ゲーミフィケーション要素の採用促進研究','Research on Gamification Elements in Adoption Promotion','ゲーミフィケーション（ポイント・バッジ・ランキング・ナラティブ）がシステム・サービスの採用と継続使用に与える効果を分析した研究群。内発的動機・コンピテンス感・自律性の媒介効果が確認され、ゲーミフィケーションの効果が文脈依存的であることも示された。','EdTech・ヘルスアプリ・企業トレーニングシステムのエンゲージメント設計に貢献した。','diffusion_adoption_user','C_processes','ゲーミフィケーション採用研究','2012','micro','adoption','gamification_motivation','["Hamari, J.", "Koivisto, J.", "Deterding, S."]','["Hamari et al. (2014) Gamification meta-analysis", "Deterding et al. (2011) Gamification definition"]','ゲーミフィケーション,採用促進,内発的動機,エンゲージメント','gamification,adoption promotion,intrinsic motivation,engagement'),
('inno_diff_241','デジタルツイン技術採用の産業研究','Industrial Adoption Research on Digital Twin Technology','製造業・都市計画・インフラ管理におけるデジタルツイン技術の採用規定因を分析した研究群。IoTセンサー統合・シミュレーション精度・データガバナンス・ROI可視化が主要テーマとなっている。インダストリー4.0戦略との接続も議論されている。','製造業のスマートファクトリー化と都市インフラ管理のデジタル化政策に貢献した。','diffusion_adoption_user','C_processes','インダストリー4.0採用研究','2018','meso','adoption','industrial_technology_adoption','["Grieves, M.", "Vickers, J.", "Tao, F."]','["Grieves & Vickers (2017) Digital Twin origins", "Tao et al. (2018) Digital Twin manufacturing"]','デジタルツイン,スマートファクトリー,IoT統合,産業採用','digital twin,smart factory,IoT integration,industrial adoption'),
('inno_diff_242','量子コンピューティング採用の初期市場研究','Early Market Research on Quantum Computing Adoption','量子コンピューティングの初期採用者（IBM Quantum・Google Quantum AI・IonQ利用企業）の採用動機・障壁・期待を分析した探索的研究群。技術成熟度（TRL）・人材確保・量子優位性の実証が主要テーマとなっている。クラシカルHPC利用経験が量子採用の強力な先行要因として確認されている。','量子コンピューティング産業政策・企業のQuantum Readiness戦略に初期知見を提供した。','diffusion_adoption_user','C_processes','新興技術初期採用研究','2019','meso','adoption','early_adopter_technology','["Preskill, J.", "Montanaro, A.", "Zeng, B."]','["Preskill (2018) Quantum computing NISQ era", "Montanaro (2016) Quantum algorithms"]','量子コンピューティング,初期採用,量子優位性,NISQ','quantum computing,early adoption,quantum advantage,NISQ'),
('inno_diff_243','サイバーセキュリティ技術採用の組織研究','Organizational Research on Cybersecurity Technology Adoption','SIEM・EDR・ゼロトラストアーキテクチャなどセキュリティ技術の組織採用を分析した研究群。リスク認知・コンプライアンス圧力・CISO権限・予算制約が採用規定因として確認されている。セキュリティ文化と技術採用の相互影響も重要テーマとなっている。','組織のサイバーセキュリティ戦略と情報セキュリティ政策立案に実証的根拠を提供した。','diffusion_adoption_user','C_processes','サイバーセキュリティ採用研究','2015','meso','adoption','risk_perception_adoption','["Bulgurcu, B.", "Cavusoglu, H.", "Benbasat, I."]','["Bulgurcu et al. (2010) IS security policy compliance", "Cavusoglu et al. (2004) Security investment"]','サイバーセキュリティ,ゼロトラスト,リスク認知,CISO','cybersecurity,zero trust,risk perception,CISO'),
('inno_diff_244','ナノテクノロジー採用の公衆リスク認知研究','Public Risk Perception Research on Nanotechnology Adoption','ナノ材料・ナノ医薬品・ナノ食品への公衆受容とリスク認知を分析した研究群。技術への信頼・便益認知・不確実性忌避・メディアフレームが受容態度に影響することが示された。ヨーロッパと米国の比較研究が特に蓄積されている。','ナノテクノロジー規制政策とリスクコミュニケーション戦略の科学的根拠を提供した。','diffusion_adoption_user','C_processes','公衆技術受容・リスク認知研究','2006','micro','adoption','risk_benefit_framing','["Kahan, D.M.", "Siegrist, M.", "Slovic, P."]','["Kahan et al. (2007) Nanotechnology risk", "Siegrist et al. (2008) Nanotechnology acceptance"]','ナノテクノロジー,公衆受容,リスク認知,不確実性','nanotechnology,public acceptance,risk perception,uncertainty'),
('inno_diff_245','遺伝子組換え食品採用の消費者研究','Consumer Research on Genetically Modified Food Adoption','GM食品の消費者受容・購買意図・WTP（支払意思額）を分析した研究群。自然性規範・情報効果・ラベリング政策・文化的価値が受容態度に影響することが示された。欧米とアジアで受容パターンが大きく異なることも確認されている。','GM食品規制・ラベリング政策・農業バイオテクノロジー産業の市場戦略に貢献した。','diffusion_adoption_user','C_processes','バイオテクノロジー受容研究','1998','micro','adoption','naturalistic_adoption_barrier','["Bredahl, L.", "Frewer, L.J.", "Grunert, K.G."]','["Bredahl (2001) GM food attitudes", "Frewer et al. (2004) GM food acceptance"]','GM食品,遺伝子組換え,消費者受容,ラベリング','GM food,genetically modified,consumer acceptance,labeling'),
('inno_diff_246','スマート農業採用の先進国実証研究','Empirical Research on Smart Agriculture Adoption in Developed Countries','EU・米国・オーストラリアの農家による精密農業・センサー農業・AI営農支援採用を分析した研究群。農場規模・農家年齢・農業経営の市場志向性・補助金設計が採用規定因として確認されている。データ所有権問題も新たな採用障壁として浮上している。','先進国の農業政策（EU共通農業政策改革等）とアグリテック企業の市場戦略に貢献した。','diffusion_adoption_user','C_processes','アグリテック採用研究（先進国）','2015','meso','adoption','farm_scale_adoption','["Barnes, A.P.", "Soto, I.", "Ruiz, V."]','["Barnes et al. (2019) Smart farming adoption EU", "Soto et al. (2021) Precision agriculture barriers"]','スマート農業,精密農業,アグリテック,データ所有権','smart farming,precision agriculture,agritech,data ownership'),
('inno_diff_247','ゲノム医療・精密医療採用の医療従事者研究','Healthcare Provider Adoption of Genomic Medicine and Precision Medicine','NGS（次世代シーケンシング）・薬理ゲノミクス・液体生検などゲノム医療ツールの臨床採用を分析した研究群。遺伝子相談専門知識不足・保険償還未整備・臨床エビデンス不確実性が主要障壁として確認されている。患者への結果開示プロセスも重要なテーマとなっている。','ゲノム医療推進政策・医師教育プログラム設計・医療保険カバレッジ決定に貢献した。','diffusion_adoption_user','C_processes','ゲノム医療採用研究','2014','meso','adoption','knowledge_gap_adoption','["Green, R.C.", "Manolio, T.A.", "Biesecker, L.G."]','["Green et al. (2013) ACMG return of results", "Manolio (2013) Genomics in clinical practice"]','ゲノム医療,精密医療,NGS,薬理ゲノミクス','genomic medicine,precision medicine,NGS,pharmacogenomics'),
('inno_diff_248','マーケットプレイス型Eコマース採用の売り手研究','Seller Adoption Research on Marketplace E-Commerce','Amazon・Alibaba・eBayなどマーケットプレイスへの売り手（SME）採用と離脱行動を分析した研究群。プラットフォームガバナンス・手数料透明性・アルゴリズム可視性・顧客関係所有権が採用継続に影響することが示された。','Eコマースプラットフォームのガバナンス設計と中小企業デジタル化支援政策に貢献した。','diffusion_adoption_user','C_processes','Eコマースプラットフォーム採用研究','2012','meso','adoption','platform_governance_adoption','["Zhu, F.", "Liu, Q.", "Hagiu, A."]','["Zhu & Liu (2018) Competing with complementors", "Hagiu & Wright (2015) Multi-sided platforms"]','Eコマース,マーケットプレイス,売り手採用,プラットフォームガバナンス','e-commerce,marketplace,seller adoption,platform governance'),
('inno_diff_249','デジタルツール採用の心理的エンパワーメント研究','Psychological Empowerment Research on Digital Tool Adoption','デジタルツール採用が利用者の心理的エンパワーメント（意味感・能力感・自己決定感・影響力感）を高めるメカニズムを分析した研究群。Thomasらのエンパワーメント理論をIT採用文脈に適用し、採用後の職業的成長との関連も検討されている。','企業のデジタル研修設計と組織開発の心理的根拠を提供した。','diffusion_adoption_user','C_processes','心理的エンパワーメント採用研究','2007','micro','adoption','empowerment_adoption','["Thomas, K.W.", "Velthouse, B.A.", "Spreitzer, G.M."]','["Thomas & Velthouse (1990) Empowerment model", "Spreitzer (1995) Psychological empowerment"]','心理的エンパワーメント,デジタルツール採用,自己決定,能力感','psychological empowerment,digital tool adoption,self-determination,competence'),
('inno_diff_250','AIモデル採用の倫理的受容研究','Ethical Acceptance Research on AI Model Adoption','AIシステムへの採用において、アルゴリズム公正性・説明可能性・データプライバシー・自律性への不安が採用態度に与える影響を分析した研究群。EU AI規制法（AI Act）施行後の企業・消費者の採用行動変化の研究も含まれる。','Responsible AI政策と企業のAIガバナンス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','AI倫理・採用研究','2019','micro','adoption','ethical_ai_adoption','["Jobin, A.", "Ienca, M.", "Vayena, E."]','["Jobin et al. (2019) Global AI ethics", "Vayena et al. (2018) AI in health ethics"]','AI倫理,説明可能性,アルゴリズム公正性,採用受容','AI ethics,explainability,algorithmic fairness,adoption acceptance');
